  ('elementary-7fec267e-moex-00025', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '下列關於國際人權公約在我國實踐之敘述，何者錯誤？', '["我國並非聯合國會員國，故批准國際人權公約後無法存放於聯合國", "我國主動邀請國際人權專家至我國審查並提供觀察報告，以代替聯合國國家報告審查", "我國依憲法由立法院依條約案審議程序，主動將人權公約國內法化", "經過我國國內法化之國際人權公約，在規範效力上具有法律的位階"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00026', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '關於法律的位階，下列何者錯誤？', '["特別法的位階高於普通法", "經立法院通過之國際條約位階等同法律", "法律的位階高於法規命令", "法規命令與憲法牴觸無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00027', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '大學生甲認為學校不允許他在學校布告欄張貼支持某政治人物的海報，侵害其言論自由。下列關於救濟途 徑的敘述，何者正確？', '["甲沒有被退學，故不能救濟", "甲應該先向學校提起申訴", "甲得逕向行政法院提起行政訴訟", "甲得逕向憲法法庭聲請判決其基本權是否受侵害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00028', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '關於憲法明定之救濟權利，下列何者錯誤？', '["訴訟", "訴願", "請願", "陳情"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
