  ('elementary-7fec267e-moex-00030', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '國際政治的權力結構是一個動態體系，關於國際政治體系的發展歷程，下列敘述何者正確？', '["冷戰時期的單極體系，指美國在軍事、科技和經濟各方面領先全球", "蘇聯共產政權瓦解後，國際政治權力結構走向多極體系的國際合作", "二次世界大戰後，資本主義與共產主義兩大陣營對峙長達半個世紀", "中國崛起成為世界工廠與世界市場，國際體系轉變為中美兩極對抗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00031', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '下列有關我國民法侵權行為責任規定之敘述，何者錯誤？', '["無行為能力人或限制行為能力人，不法侵害他人之權利者，不論其行為時是否有識別能力，皆應與其法 定代理人連帶負損害賠償責任", "無行為能力人或限制行為能力人，不法侵害他人之權利時，如法定代理人能主張其監督並未疏懈，即不 負賠償責任", "僱用人賠償損害時，對於為侵權行為之受僱人，有求償權", "承攬人因執行承攬事項，不法侵害他人權利時，除非定作人於定作或指示有過失，否則定作人不負損害 賠償責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00032', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-b3f42868', 'sub-elementary-7fec267e-01', NULL, 'single_choice', '小明騎機車紅燈右轉，被警察開罰單。小明不服，雖依規定提出申訴，但遭到駁回。如果小明想繼續救濟， 主張撤銷該罰單，應向下列那個法院起訴？', '["地方法院刑事庭", "地方法院簡易庭", "高等行政法院高等行政訴訟庭", "高等行政法院地方行政訴訟庭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "e1455ee2159f", "answer_pdf_sha1": "c91e411dad10", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
